import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium plus processing fee for a single sword (new customer, first contract)");
    it.todo("should return base premium plus processing fee for a single amulet");
    it.todo("should return base premium plus processing fee for a single component");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% multi-contract discount for second contract onwards");
    it.todo("should sum premiums for multiple items in one quote");
  });

  describe("claim", () => {
    it.todo("should pay out damage minus deductible for a basic claim");
    it.todo("should return zero payout when damage is less than or equal to deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should reimburse fully for items made of dragon material");
    it.todo("should reduce remaining cap across multiple claims on the same policy");
  });
});

