const INITIAL_ASSESSMENT_SURCHARGE = 1.10;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  component: 25,
};

const ceilG = (amount: number): number => Math.ceil(Math.round(amount * 100) / 100);

export const quote = (customer: unknown, items: { type: string }[]): number => {
  const basePremium = BASE_PREMIUMS[items[0].type];
  return ceilG(basePremium * INITIAL_ASSESSMENT_SURCHARGE) + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

